const filename = $input.item.json.name || '';
const fileId   = $input.item.json.id   || '';

function normalizePhone(raw) {
  if (!raw) return null;
  const cleaned = raw.replace(/[\s\-\(\)]/g, '');
  if (raw.startsWith('+64'))              return raw.replace(/[\s\-\(\)]/g, '');
  if (cleaned.startsWith('64') && cleaned.length >= 11) return '+' + cleaned;
  if (cleaned.startsWith('0'))            return '+64' + cleaned.slice(1);
  return null;
}

// Oppo A5 built-in recorder format: {phone_number}-YYMMDDHHMM.awb
// e.g. +6421XXXXXXX-2603112045.awb
let phoneRaw = null;
let callDate = new Date().toISOString().slice(0, 10);

const nameNoExt = filename.replace(/\.\w+$/, '');
const parts = nameNoExt.split('-');
const lastPart = parts[parts.length - 1];

if (/^\d{10}$/.test(lastPart)) {
  // Last segment is YYMMDDHHMM timestamp
  const yy = lastPart.slice(0, 2);
  const mm = lastPart.slice(2, 4);
  const dd = lastPart.slice(4, 6);
  callDate = `20${yy}-${mm}-${dd}`;
  phoneRaw = parts.slice(0, -1).join('-');
} else {
  // Fallback: regex scan for phone number anywhere in filename
  const e164Match = filename.match(/\+64\d{8,10}/);
  if (e164Match) {
    phoneRaw = e164Match[0];
  } else {
    const localMatch = filename.match(/0[2-9]\d{7,9}/);
    if (localMatch) phoneRaw = localMatch[0];
  }
  // Fallback date: YYYYMMDD pattern
  const dateMatch = filename.match(/(\d{8})/);
  if (dateMatch) {
    const rawDate = dateMatch[1];
    callDate = `${rawDate.slice(0,4)}-${rawDate.slice(4,6)}-${rawDate.slice(6,8)}`;
  }
}

const phone = phoneRaw ? normalizePhone(phoneRaw) : null;

return [{ json: { file_id: fileId, filename, phone_e164: phone, call_date: callDate } }];

const phone = $('Extract Phone').item.json.phone_e164;

// No phone in filename — not a trackable call
if (!phone) {
  return [{ json: { matched: false, lead_name: null, lead_agency: null, lead_mobile: null } }];
}

function normalize(p) {
  if (!p) return '';
  return p.replace(/[\s\-\(\)]/g, '').replace(/^\+64/, '0').replace(/^64/, '0');
}

const target = normalize(phone);
const rows   = $input.all();
let match    = null;

for (const item of rows) {
  const mobile = (item.json['Mobile'] || '').trim();
  if (normalize(mobile) === target) { match = item.json; break; }
}

if (!match) {
  return [{ json: { matched: false, lead_name: null, lead_agency: null, lead_mobile: null } }];
}

return [{ json: {
  matched:      true,
  lead_name:    match['Name']   || 'Unknown',
  lead_agency:  match['Agency'] || '',
  lead_mobile:  match['Mobile'] || phone,
  lead_city:    match['City']   || '',
  lead_email:   match['Email']  || '',
}}];

// Formats AssemblyAI completed transcript.
// If speaker diarization is available, outputs "Speaker A: ..." lines.
// Falls back to plain text if utterances are missing.
const json = $input.item.json;

let transcript = '';
if (Array.isArray(json.utterances) && json.utterances.length > 0) {
  transcript = json.utterances
    .map(u => `Speaker ${u.speaker}: ${u.text}`)
    .join('\n');
} else {
  transcript = json.text || '';
}

return [{ json: { transcript } }];

const lead      = $('Match Lead').item.json;
const callDate  = $('Extract Phone').item.json.call_date;
const transcript = $('Extract Transcript').item.json.transcript || '';

const prompt = `You are an assistant to an automation developer in New Zealand who works with real estate agents.

Analyse this discovery call transcript and return ONLY valid JSON with this exact structure:

{
  "summary": "2-3 sentence summary of the call",
  "pain_points": ["pain point 1", "pain point 2"],
  "crm_tools": ["tool/CRM name"],
  "agent_type": "e.g. Independent, Franchise, Residential, Commercial, Development",
  "team_size": "e.g. Solo, 2-5, 5+",
  "interest_level": "Hot | Warm | Cold",
  "interest_reasoning": "1-2 sentences explaining why",
  "suggested_automations": [
    {"name": "automation name", "description": "how it would help this specific agent"}
  ],
  "next_steps": ["specific action 1", "specific action 2"],
  "objections": ["objection 1 if any"]
}

Context:
- Lead name: ${lead.lead_name}
- Agency: ${lead.lead_agency || 'Unknown'}
- Call date: ${callDate}
- NZ real estate CRMs to watch for: ARO Software, Rex, PropertyMe, Agentbox, MyDesktop, Vault
- Common pain points: enquiry follow-up speed, appraisal prep, listing admin, open home follow-up, buyer nurturing
- Automation pitch framing: human-in-the-loop — agent approves everything
- Transcript may use "Speaker A / Speaker B" labels — Speaker A is typically Brandon (the caller), Speaker B is the agent (the lead)

Transcript:
${transcript}`;

return [{ json: { prompt } }];

const json      = $input.item.json;
const lead      = $('Match Lead').item.json;
const phoneMeta = $('Extract Phone').item.json;
const transcript = $('Extract Transcript').item.json.transcript || '';

// Anthropic node returns json.text; OpenAI node returns json.message.content
let raw = json.text || (json.message && json.message.content) || '';
raw = raw.trim().replace(/^```json?\s*/i, '').replace(/\s*```$/, '');

let a;
try {
  a = JSON.parse(raw);
} catch(e) {
  a = {
    summary: 'Parse error — review transcript manually',
    pain_points: [], crm_tools: [], agent_type: 'Unknown',
    team_size: 'Unknown', interest_level: 'Unknown',
    interest_reasoning: '', suggested_automations: [],
    next_steps: ['Review transcript manually'], objections: [],
  };
}

const arr = (v) => Array.isArray(v) ? v : [];

const pain_str = arr(a.pain_points).join('; ');
const crm_str  = arr(a.crm_tools).join(', ');
const auto_str = arr(a.suggested_automations)
  .map(x => typeof x === 'object' ? `${x.name}: ${x.description}` : String(x))
  .join(' | ');
const next_str = arr(a.next_steps).join(' | ');
const obj_str  = arr(a.objections).join('; ');

const sms_body = [
  `Call: ${lead.lead_name} (${lead.lead_agency || 'Unknown agency'}) — ${phoneMeta.call_date}`,
  `Interest: ${a.interest_level} — ${a.interest_reasoning || ''}`,
  `Pain: ${arr(a.pain_points).slice(0, 2).join(', ') || 'See report'}`,
  `Next: ${arr(a.next_steps)[0] || 'Review notes'}`,
].join('\n');

return [{ json: {
  // Structured analysis
  summary:                  a.summary || '',
  pain_points_str:          pain_str,
  crm_tools_str:            crm_str,
  agent_type:               a.agent_type || '',
  team_size:                a.team_size || '',
  interest_level:           a.interest_level || '',
  interest_reasoning:       a.interest_reasoning || '',
  suggested_automations_str: auto_str,
  next_steps_str:           next_str,
  objections_str:           obj_str,
  // Lead context
  lead_name:    lead.lead_name,
  lead_agency:  lead.lead_agency,
  lead_mobile:  lead.lead_mobile,
  call_date:    phoneMeta.call_date,
  file_id:      phoneMeta.file_id,
  // Full transcript
  transcript,
  // SMS
  sms_body,
}}];

